// *highlighted section* Function to generate a complex sequence
vector<int> generateComplexSequence(int n) {
    vector<int> sequence;
    for (int i = 1; i <= n; ++i) {
        int val = 0;
        for (int j = 1; j <= i; ++j) {
            val += pow(j, 2) * (i - j + 1);
        }
        sequence.push_back(val);
    }
    return sequence;
}

