void printPattern(const vector<int>& sequence) {
    int maxLen = 0;
    for (int num : sequence) {
        maxLen = max(maxLen, to_string(num).length());
    }

    for (int i = 0; i < sequence.size(); ++i) {
        cout << setw(maxLen) << sequence[i];
        if (i < sequence.size() - 1) {
            cout << " ";
        }
    }
    cout << endl;
}

